import React, { useState } from "react";
import api from "../../api";

const emailTemplates = {
  promo: {
    name: "🎁 Khuyến mãi",
    templateName: "promo",
    html: `
      <h1 style="color:#e06c7f;">🌸 Ưu đãi đặc biệt!</h1>
      <p>Giảm <strong>20%</strong> đơn hàng hoa tươi hôm nay 💐</p>
    `,
  },
  holiday: {
    name: "🎄 Lễ tết",
    templateName: "holiday",
    html: `
      <h1 style="color:#e06c7f;">🎄 Chúc mừng năm mới!</h1>
      <p>Hoa tươi giảm 15% toàn bộ cửa hàng!</p>
    `,
  },
  birthday: {
    name: "🎂 Sinh nhật",
    templateName: "birthday",
    html: `
      <h1 style="color:#e06c7f;">🎂 Happy Birthday!</h1>
      <p>Tặng bạn voucher 10% 🎁</p>
    `,
  },
};

const SendEmailPage = () => {
  const [subject, setSubject] = useState("");
  const [group, setGroup] = useState("all");
  const [template, setTemplate] = useState("promo");
  const [customHtml, setCustomHtml] = useState("");
  const [sending, setSending] = useState(false);
  const [message, setMessage] = useState("");

  const handleSend = async () => {
    setSending(true);
    setMessage("");

    const selectedTemplate =
      template === "custom"
        ? {
            html: customHtml,
            templateName: "custom",
          }
        : emailTemplates[template];

    if (!subject || !selectedTemplate.html) {
      setMessage("❌ Thiếu tiêu đề hoặc nội dung!");
      setSending(false);
      return;
    }

    try {
      const res = await api.post("/email/send", {
        subject,
        group,
        template: selectedTemplate.html,
        templateName: selectedTemplate.templateName,
      });

      setMessage(res.data.message);
    } catch (err) {
      console.error(err);
      setMessage("❌ Gửi email thất bại!");
    }

    setSending(false);
  };

  const previewHtml =
    template === "custom"
      ? customHtml || "<p>Nhập HTML…</p>"
      : emailTemplates[template].html;

  return (
    <div className="p-8">
      <h1 className="text-3xl font-bold text-[#e06c7f] mb-8">
        📩 Gửi Email Marketing
      </h1>

      <div className="bg-white p-6 rounded-xl shadow-lg max-w-3xl">

        {/* SUBJECT */}
        <label className="font-medium">Tiêu đề Email</label>
        <input
          className="w-full border p-3 rounded-lg mb-4"
          placeholder="Nhập tiêu đề..."
          value={subject}
          onChange={(e) => setSubject(e.target.value)}
        />

        {/* GROUP */}
        <label className="font-medium">Gửi đến nhóm</label>
        <select
          className="w-full border p-3 rounded-lg mb-4"
          value={group}
          onChange={(e) => setGroup(e.target.value)}
        >
          <option value="all">📢 Tất cả</option>
          <option value="user">👤 User</option>
          <option value="vip">👑 VIP</option>
          <option value="newsletter">📰 Newsletter</option>
          <option value="admin">🛠 Admin</option>
        </select>

        {/* TEMPLATE */}
        <label className="font-medium">Mẫu email</label>
        <select
          className="w-full border p-3 rounded-lg mb-4"
          value={template}
          onChange={(e) => setTemplate(e.target.value)}
        >
          {Object.entries(emailTemplates).map(([key, t]) => (
            <option value={key} key={key}>
              {t.name}
            </option>
          ))}
          <option value="custom">✍ Tự nhập HTML</option>
        </select>

        {/* CUSTOM HTML */}
        {template === "custom" && (
          <textarea
            className="w-full border p-3 rounded-lg mb-4 h-40"
            placeholder="Nhập HTML..."
            value={customHtml}
            onChange={(e) => setCustomHtml(e.target.value)}
          />
        )}

        <button
          onClick={handleSend}
          disabled={sending}
          className="w-full py-3 bg-[#e06c7f] text-white rounded-lg"
        >
          {sending ? "Đang gửi…" : "📨 Gửi Email"}
        </button>

        {message && (
          <div className="mt-4 p-3 bg-green-100 border border-green-300 text-green-700 rounded-lg">
            {message}
          </div>
        )}
      </div>

      {/* PREVIEW */}
      <div className="mt-8 bg-[#faf8f6] border p-6 rounded-xl">
        <h2 className="text-xl font-semibold mb-3">👀 Preview</h2>

        <div
          className="border bg-white rounded-lg p-5 shadow-sm"
          dangerouslySetInnerHTML={{ __html: previewHtml }}
        />
      </div>
    </div>
  );
};

export default SendEmailPage;
